  @override Widget build(BuildContext context){
    final seed = const Color(0xff00d49a);
    final theme = ThemeData(useMaterial3:true, colorScheme: ColorScheme.fromSeed(seedColor: seed, brightness: dark?Brightness.dark:Brightness.light), fontFamily:'Tahoma', scaffoldBackgroundColor: dark?const Color(0xff07111f):const Color(0xfff3f8ff));
