      title:'قل‌قلی', debugShowCheckedModeBanner:false, locale:const Locale('fa'), supportedLocales:const [Locale('fa')], localizationsDelegates:const [GlobalMaterialLocalizations.delegate,GlobalWidgetsLocalizations.delegate,GlobalCupertinoLocalizations.delegate],
