      home: !ready ? const Splash() : api.token==null ? AuthScreen(api:api,onDone:()=>setState((){})) : HomeShell(api:api,onLogout:()async{await api.logout();setState((){});},dark:dark,onTheme:()=>setState(()=>dark=!dark)),
    );
  }
}
